module binary_counter(
	input clk,
	input reset_n,
	input enable,
	output reg [2:0] count);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt)
	if (!reset_n)
		count <= 0;
	else if (enable)
		count <= count + 1;

endmodule
